    Milkshake & Tea & Milkshake & Tea & Coffee & Tea & Milkshake & Coffee
    \end{tabular}
    \end{center}

    \begin{subparts}
        \subpart Complete the frequency table.

        You may use the tally column to help you.

        \begin{center}
        \begin{tabular}{|l|c|c|}
        \hline
        Drink & Tally & Frequency \\
        \hline
        Coffee & & \\
        \hline
        Juice & & \\
        \hline
        Milkshake & & \\
        \hline
        Tea & & \\
        \hline
        & Total & 24 \\
        \hline
        \end{tabular}
        \end{center}
        \Marks{2}

        \subpart Draw a bar chart to show this information.

        Complete the scale on the frequency axis.
        \Marks{3}
    \end{subparts}

    \item This table shows the opening hours of the café.

    \begin{center}
    \begin{tabular}{|l|c|}
    \hline
    Day & Opening hours \\
    \hline
    Monday to Thursday & 08\,30 to 17\,00 \\
    \hline
    Friday and Saturday & 08\,30 to 19\,00 \\
    \hline
    Sunday & 09\,00 to 18\,00 \\
    \hline
    \end{tabular}
    \end{center}

    \begin{subparts}
        \subpart Work out the total number of hours the café is open in one week.
        \AnswerLine[][hours]
        \Marks{2}

        \subpart Lena is in the café for 40 hours each week.

        Ron is in the café when Lena is not there.

        Calculate the percentage of the total opening hours that Ron is in the café each week.
        \AnswerLine[][\%]
        \Marks{2}
    \end{subparts}

    \item Saddak buys 3 cups of tea and 2 cookies for \$6.95.

    A cup of tea costs \$1.75.

    Work out the cost of one cookie.
    \AnswerLine[\$][]
    \Marks{2}

    \item The price of a cake is \$2.60.

    At the end of the day, Lena reduces the price of each cake by 35\%.

    Calculate the reduced price of a cake.
    \AnswerLine[\$][]
    \Marks{2}
\end{parts}

