\begin{parts}
    \item The table gives some information about the numbers of visitors at a leisure centre one day.

    \begin{center}
    \begin{tabular}{|l|c|c|c|}
    \hline
    & Adult & Child & Total \\
    \hline
    Male & & 144 & 240 \\
    \hline
    Female & 129 & & 260 \\
    \hline
    Total & 225 & 275 & 500 \\
    \hline
    \end{tabular}
    \end{center}

    \begin{subparts}
        \subpart Complete the table.
        \Marks{1}

        \subpart Work out how many more child visitors than adult visitors there are.
        \AnswerLine[][]
        \Marks{1}

        \subpart Write down the fraction of visitors that are adults.

        Give your answer in its lowest terms.
        \AnswerLine[][]
        \Marks{2}

        \subpart Write the ratio \quad number of males : number of females.

        Give your answer in its simplest form.
        \AnswerLine[][ : ]
        \Marks{2}

        \subpart One of these visitors is selected at random.

        Find the probability that this visitor is a male child.
        \AnswerLine[][]
        \Marks{1}
    \end{subparts}

    \item The number of people in each of 150 cars entering the leisure centre car park is recorded.

    The table shows the results.

    \begin{center}
    \begin{tabular}{|l|c|c|c|c|c|}
    \hline
    Number of people & 1 & 2 & 3 & 4 & 5 \\
    \hline
    Frequency & 44 & 43 & 30 & 25 & 8 \\
    \hline
    \end{tabular}
    \end{center}

    \begin{subparts}
        \subpart Write down the mode.
        \AnswerLine[][]
        \Marks{1}

        \subpart Calculate the mean.
        \AnswerLine[][]
        \Marks{3}
    \end{subparts}

    \item In a survey of 50 visitors to the leisure centre, 18 used the gym.

    One day, 1500 people visited the leisure centre.

    Calculate an estimate for the number of people who used the gym on this day.
    \AnswerLine[][]
    \Marks{2}
\end{parts}

